#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int ans;
int main()
{
	for (int t = read(), n; t; --t)
	{
		ans = 1;
		n = read();
		if (n < 6)
		{
			puts("-1");
			continue;
		}
		for (int i = 2; i * i <= n; ++i)
		{
			if (n % i == 0 && n / i > 5)
			{
				ans = max(ans, i);
				if (i > 5)
				{
					ans = max(ans, n / i);
				}
			}
		}
		write(ans);
		puts("");
	}
	return false;
}
